import{_ as n,o as s,c as a,e}from"./app-25fa875f.js";const t={},i=e(`<h1 id="solidity-layout-and-structure" tabindex="-1"><a class="header-anchor" href="#solidity-layout-and-structure" aria-hidden="true">#</a> Solidity - Layout and Structure</h1><p>Created by : Mr Dk.</p><p>2020 / 02 / 25 20:49</p><p>Ningbo, Zhejiang, China</p><hr><h2 id="pragmas" tabindex="-1"><a class="header-anchor" href="#pragmas" aria-hidden="true">#</a> Pragmas</h2><p>编译标记只针对当前源代码文件有效。</p><h3 id="version-pragma" tabindex="-1"><a class="header-anchor" href="#version-pragma" aria-hidden="true">#</a> Version Pragma</h3><p>用于使旧的编译器拒绝编译一些新的特性。常用方法：</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">^</span><span class="token version number">0.5.2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="experimental-pragma" tabindex="-1"><a class="header-anchor" href="#experimental-pragma" aria-hidden="true">#</a> Experimental Pragma</h3><p>用于开启一些编译器或语言中默认没有启动的特性。</p><ul><li>ABIEncoderV2</li><li>SMTChecker</li></ul><hr><h2 id="importing-other-source-files" tabindex="-1"><a class="header-anchor" href="#importing-other-source-files" aria-hidden="true">#</a> Importing other Source Files</h2><h3 id="syntax-and-semantics" tabindex="-1"><a class="header-anchor" href="#syntax-and-semantics" aria-hidden="true">#</a> Syntax and Semantics</h3><p>引入其它源文件，从而获得更好的模块化。</p><p>全局模式：</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">import</span> <span class="token string">&quot;filename&quot;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>但是这种模式可能带来的问题就是，在 <code>filename</code> 中引入的变量会被自动引入到所有引用它的文件中，可能会带来命名冲突的隐患。可以通过给创建新的全局命名符号来表示 <code>filename</code> 中的变量：</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> symbolName <span class="token keyword">from</span> <span class="token string">&quot;filename&quot;</span><span class="token punctuation">;</span>
<span class="token comment">// or</span>
<span class="token keyword">import</span> <span class="token string">&quot;filename&quot;</span> <span class="token keyword">as</span> symbolName<span class="token punctuation">;</span>
<span class="token comment">// symbolName.synbol</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果命名符号存在冲突，或者只想引入某几个变量，可以这样：</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">import</span> <span class="token punctuation">{</span>symbol1 <span class="token keyword">as</span> alias<span class="token punctuation">,</span> symbol2<span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&quot;filename&quot;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="path" tabindex="-1"><a class="header-anchor" href="#path" aria-hidden="true">#</a> Path</h3><p>除了 <code>.</code> 和 <code>..</code> 开头的路径以外，所有的路径都会被视为绝对路径。但一般是由编译器决定如何解析路径。</p><hr><h2 id="comments" tabindex="-1"><a class="header-anchor" href="#comments" aria-hidden="true">#</a> Comments</h2><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token comment">// 单行注释</span>

<span class="token comment">/*
多行注释
*/</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另外还支持一种注释，只能标注在 contract 或方法名上，我一看这不就是 Javadoc 嘛......功能也类似，用于标注文档：</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token comment">/** @title Calculator */</span>

<span class="token comment">/// @dev ...</span>
<span class="token comment">/// @param w ...</span>
<span class="token comment">/// @return res ...</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="structure" tabindex="-1"><a class="header-anchor" href="#structure" aria-hidden="true">#</a> Structure</h2><p>Contract 与 OOP 语言的 <strong>类</strong> 类似。另外，一个 contract 可以继承自其它 contract。此外，还有特殊种类的 contract - libraries 和 interfaces。</p><h3 id="state-variables" tabindex="-1"><a class="header-anchor" href="#state-variables" aria-hidden="true">#</a> State Variables</h3><p>状态变量的值将会永远被存放在 contract 存储中。</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.0</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">SimpleStorage</span> <span class="token punctuation">{</span>
    <span class="token builtin">uint</span> storedData<span class="token punctuation">;</span> <span class="token comment">// State variable</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="functions" tabindex="-1"><a class="header-anchor" href="#functions" aria-hidden="true">#</a> Functions</h3><p>Contract 内可被执行的单元。</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.0</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">SimpleAuction</span> <span class="token punctuation">{</span>
    <span class="token keyword">function</span> <span class="token function">bid</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">public</span> <span class="token keyword">payable</span> <span class="token punctuation">{</span> <span class="token comment">// Function</span>
        <span class="token comment">// ...</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="function-modifiers" tabindex="-1"><a class="header-anchor" href="#function-modifiers" aria-hidden="true">#</a> Function Modifiers</h3><p>以一种声明式的方式修改函数的语义。</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.22</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">Purchase</span> <span class="token punctuation">{</span>
    <span class="token builtin">address</span> <span class="token keyword">public</span> seller<span class="token punctuation">;</span>

    <span class="token keyword">modifier</span> <span class="token function">onlySeller</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// Modifier</span>
        <span class="token keyword">require</span><span class="token punctuation">(</span>
            msg<span class="token punctuation">.</span>sender <span class="token operator">==</span> seller<span class="token punctuation">,</span>
            <span class="token string">&quot;Only seller can call this.&quot;</span>
        <span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">_</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">function</span> <span class="token function">abort</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">public</span> <span class="token keyword">view</span> onlySeller <span class="token punctuation">{</span> <span class="token comment">// Modifier usage</span>
        <span class="token comment">// ...</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="events" tabindex="-1"><a class="header-anchor" href="#events" aria-hidden="true">#</a> Events</h3><p>是 EVM 用于进行日志记录的工具。</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.21</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">SimpleAuction</span> <span class="token punctuation">{</span>
    <span class="token keyword">event</span> <span class="token function">HighestBidIncreased</span><span class="token punctuation">(</span><span class="token builtin">address</span> bidder<span class="token punctuation">,</span> <span class="token builtin">uint</span> amount<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Event</span>

    <span class="token keyword">function</span> <span class="token function">bid</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">public</span> <span class="token keyword">payable</span> <span class="token punctuation">{</span>
        <span class="token comment">// ...</span>
        <span class="token keyword">emit</span> <span class="token function">HighestBidIncreased</span><span class="token punctuation">(</span>msg<span class="token punctuation">.</span>sender<span class="token punctuation">,</span> msg<span class="token punctuation">.</span>value<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Triggering event</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="struct-types" tabindex="-1"><a class="header-anchor" href="#struct-types" aria-hidden="true">#</a> Struct Types</h3><p>结构体用于定义一些变量构成的组。</p><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.0</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">Ballot</span> <span class="token punctuation">{</span>
    <span class="token keyword">struct</span> <span class="token class-name">Voter</span> <span class="token punctuation">{</span> <span class="token comment">// Struct</span>
        <span class="token builtin">uint</span> weight<span class="token punctuation">;</span>
        <span class="token builtin">bool</span> voted<span class="token punctuation">;</span>
        <span class="token builtin">address</span> delegate<span class="token punctuation">;</span>
        <span class="token builtin">uint</span> vote<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="enum-types" tabindex="-1"><a class="header-anchor" href="#enum-types" aria-hidden="true">#</a> Enum Types</h3><div class="language-solidity line-numbers-mode" data-ext="solidity"><pre class="language-solidity"><code><span class="token keyword">pragma</span> <span class="token keyword">solidity</span> <span class="token operator">&gt;=</span><span class="token version number">0.4.0</span> <span class="token operator">&lt;</span><span class="token version number">0.7.0</span><span class="token punctuation">;</span>

<span class="token keyword">contract</span> <span class="token class-name">Purchase</span> <span class="token punctuation">{</span>
    <span class="token keyword">enum</span> <span class="token class-name">State</span> <span class="token punctuation">{</span> Created<span class="token punctuation">,</span> Locked<span class="token punctuation">,</span> Inactive <span class="token punctuation">}</span> <span class="token comment">// Enum</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr>`,51),o=[i];function l(p,c){return s(),a("div",null,o)}const r=n(t,[["render",l],["__file","Solidity Layout and Structure.html.vue"]]);export{r as default};
